import { useContext, useState, useEffect } from "react";
import { Box, Tabs, Tab, TextField, Button, Snackbar, Alert } from "@mui/material";
import { useParams, useNavigate } from "react-router-dom";
import CustomAppBar from "../../components/shared-components/AppBar/AppBar";
import DraftJsWysiwyg from "../../components/blog-components/Draft-js-wysiwyg/Draft-js-wysiwyg";
import BlogService from "../../services/BlogService";
import { SettingsContext } from "../../context/SettingsContext";
import { useUser } from "../../context/UserContext";
import { EditorState, convertToRaw, convertFromRaw } from "draft-js";

const EditBlogPage = () => {
  const navigate = useNavigate();
  const { blogID } = useParams();
  const { themeMode, language } = useContext(SettingsContext);
  const { userState } = useUser();

  const [activeTab, setActiveTab] = useState(0);
  const [tabsData, setTabsData] = useState({
    CN: { title: "", content: EditorState.createEmpty() },
    EN: { title: "", content: EditorState.createEmpty() },
  });

  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState("");
  const [snackbarSeverity, setSnackbarSeverity] = useState("success");

  const handleSnackbarClose = () => {
    setSnackbarOpen(false);
  };

  // 获取博客详情数据
  useEffect(() => {
    const fetchBlogData = async () => {
      try {
        const blogData = await BlogService.getBlog(blogID, userState.access);
        setTabsData({
          CN: {
            title: blogData.cn_title || "",
            content: EditorState.createWithContent(convertFromRaw(JSON.parse(blogData.cn_content))),
          },
          EN: {
            title: blogData.en_title || "",
            content: EditorState.createWithContent(convertFromRaw(JSON.parse(blogData.en_content))),
          },
        });
      } catch (error) {
        console.error("Error fetching blog data:", error);
      }
    };

    fetchBlogData();
  }, [blogID, userState.access]);

  const handleTabChange = (event, newValue) => {
    setActiveTab(newValue);
  };

  const handleInputChange = (langKey, field, value) => {
    setTabsData((prev) => ({
      ...prev,
      [langKey]: { ...prev[langKey], [field]: value },
    }));
  };

  const handleContentChange = (langKey, editorState) => {
    setTabsData((prev) => ({
      ...prev,
      [langKey]: { ...prev[langKey], content: editorState },
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const dataToSubmit = {
      cn_title: tabsData.CN.title,
      en_title: tabsData.EN.title,
      author: userState.username,
      cn_content: JSON.stringify(convertToRaw(tabsData.CN.content.getCurrentContent())),
      en_content: JSON.stringify(convertToRaw(tabsData.EN.content.getCurrentContent())),
    };

    try {
      await BlogService.editBlog(blogID, dataToSubmit, userState.access);
      setSnackbarMessage(language === "cn" ? "博客已更新" : "Blog updated");
      setSnackbarSeverity("success");
      setSnackbarOpen(true);
      navigate(`/blog/${blogID}`);
    } catch (error) {
      console.error("Error editing blog:", error);
      setSnackbarMessage(language === "cn" ? "更新失败" : "Failed to update blog");
      setSnackbarSeverity("error");
      setSnackbarOpen(true);
    }
  };

  const labels = {
    title: language === "cn" ? "标题" : "Title",
    content: language === "cn" ? "内容" : "Content",
    submit: language === "cn" ? "提交" : "Submit",
  };

  return (
    <Box sx={{ display: "flex", flexDirection: "column", height: "100vh", overflow: "hidden" }}>
      <CustomAppBar />
      <Box
        sx={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          maxWidth: 1000,
          width: "100%",
          mx: "auto",
          mt: 11,
          px: 2,
          overflow: "hidden",
        }}
      >
        <Tabs
          value={activeTab}
          onChange={handleTabChange}
          sx={{ flexShrink: 0 }}
          variant="fullWidth"
        >
          <Tab label="CN" />
          <Tab label="EN" />
        </Tabs>

        <Box
          component="form"
          onSubmit={handleSubmit}
          sx={{
            display: "flex",
            flexDirection: "column",
            flex: 1,
            overflow: "hidden",
          }}
        >
          <TextField
            label={
              activeTab === 0 ? `${labels.title} (CN)` : `${labels.title} (EN)`
            }
            variant="filled"
            value={activeTab === 0 ? tabsData.CN.title : tabsData.EN.title}
            onChange={(e) =>
              handleInputChange(activeTab === 0 ? "CN" : "EN", "title", e.target.value)
            }
            fullWidth
            sx={{
              flexShrink: 0,
              '& .MuiFilledInput-root': {
                backgroundColor: 'transparent',
                '&:hover': { backgroundColor: 'transparent' },
                '&.Mui-focused': { backgroundColor: 'transparent' },
              },
            }}
          />

          <Box
            sx={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              minHeight: 0,
            }}
          >
            <DraftJsWysiwyg
              editorState={activeTab === 0 ? tabsData.CN.content : tabsData.EN.content}
              onEditorStateChange={(editorState) =>
                handleContentChange(activeTab === 0 ? "CN" : "EN", editorState)
              }
            />
          </Box>

          <Box
            sx={{
              display: "flex",
              justifyContent: "flex-end",
              gap: 2,
              mt: 2,
              mb: 2,
              flexShrink: 0,
            }}
          >
            <Button type="submit" variant="contained" color="primary">
              {labels.submit}
            </Button>
          </Box>
        </Box>
      </Box>

      <Snackbar
        open={snackbarOpen}
        autoHideDuration={3000}
        onClose={handleSnackbarClose}
        anchorOrigin={{ vertical: "top", horizontal: "center" }}
      >
        <Alert severity={snackbarSeverity} sx={{ width: "100%" }}>
          {snackbarMessage}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default EditBlogPage;
